### Step 1: Define the Piece Class

```python
class Piece:
    EMPTY = ' '
    BLACK = 'B'
    WHITE = 'W'
    BLACK_KING = 'b'
    WHITE_KING = 'w'

    def __init__(self, color):
        self.color = color

    def is_king(self):
        return self.color in (Piece.BLACK_KING, Piece.WHITE_KING)

    def __str__(self):
        if self.color == Piece.EMPTY:
            return ' '
        elif self.color == Piece.BLACK:
            return 'B'
        elif self.color == Piece.WHITE:
            return 'W'
        elif self.color == Piece.BLACK_KING:
            return 'b'
        elif self.color == Piece.WHITE_KING:
            return 'w'

    def __eq__(self, other):
        if not isinstance(other, Piece):
            return False
        return self.color == other.color

    @staticmethod
    def from_char(char):
        if char in (Piece.BLACK, Piece.WHITE, Piece.BLACK_KING, Piece.WHITE_KING):
            return Piece(char)
        else:
            return None
```

### Step 2: Define the Board Class

```python
class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with alternating pieces
        for i in range(3):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = Piece(BLACK)
        for i in range(5, 8):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = Piece(WHITE)

    def print_board(self):
        for row in self.board:
            print(' '.join(str(piece) for piece in row))

    def is_valid_move(self, start, end):
        i1, j1 = start
        i2, j2 = end

        # Check if the move is within bounds
        if not (0 <= i1 < 8 and 0 <= j1 < 8 and 0 <= i2 < 8 and 0 <= j2 < 8):
            return False

        piece = self.board[i1][j1]
        if piece is None or piece.color == Piece.EMPTY:
            return False

        # Check if the move is diagonally adjacent
        if abs(i1 - i2) != 1 or abs(j1 - j2) != 1:
            return False

        # Check if the destination cell is empty
        if self.board[i2][j2] is not None and self.board[i2][j2].color == piece.color:
            return False

        # Special case for kings
        if piece.is_king():
            # Kings can move diagonally any number of squares as long as they capture
            return True

        # Check for standard captures
        if abs(i1 - i2) == 2 and abs(j1 - j2) == 2:
            capture_x, capture_y = (i1 + i2) // 2, (j1 + j2) // 2
            captured_piece = self.board[capture_x][capture_y]
            if captured_piece is None or captured_piece.color == piece.color:
                return False

        return True

    def move(self, start, end):
        i1, j1 = start
        i2, j2 = end
        piece = self.board[i1][j1]

        # Update board state
        self.board[i2][j2] = piece
        self.board[i1][j1] = None

        # Check for captures and kings
        if abs(i1 - i2) == 2:
            capture_x, capture_y = (i1 + i2) // 2, (j1 + j2) // 2
            captured_piece = self.board[capture_x][capture_y]
            self.board[capture_x][capture_y] = None

        # Kinging the piece if it reaches the opposite end
        if piece.color == BLACK and i2 == 0 or piece.color == WHITE and i2 == 7:
            self.board[i2][j2] = Piece(piece.color.upper())

    def is_game_over(self):
        black_count = sum(row.count(Piece.BLACK) for row in self.board)
        white_count = sum(row.count(Piece.WHITE) for row in self.board)

        if black_count == 0 or white_count == 0:
            return True

        # Check for valid moves
        for i in range(8):
            for j in range(8):
                if self.board[i][j] is not None and self.board[i][j].color != Piece.EMPTY:
                    for dx, dy in [(-1, -1), (-1, 1), (1, -1), (1, 1)]:
                        new_x, new_y = i + 2 * dx, j + 2 * dy
                        if self.is_valid_move((i, j), (new_x, new_y)):
                            return False

        return True
