class Player:
    def __init__(self, color):
        self.color = color

    def get_move(self, board):
        while True:
            move_input = input(f"Player {self.color}, enter your move (e.g., A1-B2): ").strip().upper()
            if len(move_input) != 5 or move_input[2] != '-':
                print("Invalid move format. Please try again.")
                continue

            start, end = move_input[:2], move_input[3:]
            i1 = ord(start[0]) - ord('A')
            j1 = int(start[1]) - 1
            i2 = ord(end[0]) - ord('A')
            j2 = int(end[1]) - 1

            if board.is_valid_move((i1, j1), (i2, j2)):
                return (i1, j1), (i2, j2)
            else:
                print("Invalid move. Please try again.")
