### Step 4: Define the Game Class

```python
class Game:
    def __init__(self):
        self.board = Board()
        self.players = {Piece.BLACK: Player(Piece.BLACK), Piece.WHITE: Player(Piece.WHITE)}
        self.current_player = Piece.BLACK

    def switch_turn(self):
        if self.current_player == Piece.BLACK:
            self.current_player = Piece.WHITE
        else:
            self.current_player = Piece.BLACK

    def play_game(self):
        while not self.board.is_game_over():
            self.board.print_board()
            player = self.players[self.current_player]
            start, end = player.get_move(self.board)
            self.board.move(start, end)
            self.switch_turn()

        if self.current_player == Piece.BLACK:
            print("White wins!")
        else:
            print("Black wins!")

if __name__ == "__main__":
    game = Game()
    game.play_game()
